import React, { useEffect, useState } from "react";
import axios from "axios";
import "./SellerDashboard.css";

const API_BASE = "http://localhost:5000/api/products"; // change port if your backend uses another port

const blankForm = {
  name: "",
  description: "",
  category: "Earphone",
  price: "",
  offerPrice: "",
  image: ""
};

function SellerDashboard() {
  const [products, setProducts] = useState([]);
  const [form, setForm] = useState(blankForm);
  const [editingProduct, setEditingProduct] = useState(null);
  const [activePage, setActivePage] = useState("add"); // 'add' or 'list'

  useEffect(() => {
    fetchProducts();
  }, []);

  const fetchProducts = async () => {
    try {
      const res = await axios.get(API_BASE);
      setProducts(res.data);
    } catch (err) {
      console.error("Fetch products error:", err.response ? err.response.data : err.message);
      alert("Failed to load products. Check console/network.");
    }
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    setForm((prev) => ({ ...prev, [name]: value }));
  };

  const normalizePayload = (f) => {
    // convert numeric fields to numbers, and include only defined fields
    const payload = {
      name: f.name,
      description: f.description,
      category: f.category,
      image: f.image
    };
    payload.price = f.price === "" ? 0 : Number(f.price);
    if (f.offerPrice !== "" && f.offerPrice != null) payload.offerPrice = Number(f.offerPrice);
    return payload;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const payload = normalizePayload(form);

    try {
      if (editingProduct) {
        const res = await axios.put(`${API_BASE}/${editingProduct._id}`, payload);
        // update local list
        setProducts((prev) => prev.map((p) => (p._id === res.data._id ? res.data : p)));
        alert("✅ Product updated!");
        setEditingProduct(null);
      } else {
        const res = await axios.post(API_BASE, payload);
        // add to top of the list
        setProducts((prev) => [res.data, ...prev]);
        alert("✅ Product added!");
      }
      setForm(blankForm);
      setActivePage("list"); // go to list so user sees result
    } catch (err) {
      console.error("Save product error:", err.response ? err.response.data : err.message);
      alert("❌ Failed to save product. Check console/network.");
    }
  };

  const handleEdit = (product) => {
    setEditingProduct(product);
    setForm({
      name: product.name || "",
      description: product.description || "",
      category: product.category || "Earphone",
      price: product.price != null ? String(product.price) : "",
      offerPrice: product.offerPrice != null ? String(product.offerPrice) : "",
      image: product.image || ""
    });
    setActivePage("add");
    window.scrollTo({ top: 0, behavior: "smooth" });
  };

  const handleCancelEdit = () => {
    setEditingProduct(null);
    setForm(blankForm);
  };

  const handleDelete = async (id) => {
    if (!window.confirm("Are you sure you want to delete this product?")) return;
    try {
      await axios.delete(`${API_BASE}/${id}`);
      setProducts((prev) => prev.filter((p) => p._id !== id));
      alert("🗑️ Product deleted");
    } catch (err) {
      console.error("Delete error:", err.response ? err.response.data : err.message);
      alert("❌ Failed to delete product. Check console/network.");
    }
  };

  return (
    <div className="seller-dashboard">
      {/* Sidebar */}
      <aside className="sidebar">
        <h1 className="logo">Seller Panel</h1>
        <nav>
          <ul>
            <li
              className={activePage === "add" ? "active" : ""}
              onClick={() => { setActivePage("add"); setEditingProduct(null); setForm(blankForm); }}
            >
              ➕ Add Product
            </li>
            <li
              className={activePage === "list" ? "active" : ""}
              onClick={() => setActivePage("list")}
            >
              📦 Product List
            </li>
            <li
              onClick={() => alert("Orders feature coming soon")}
            >
              📝 Orders
            </li>
          </ul>
        </nav>
      </aside>

      {/* Main Content */}
      <main className="main-content">
        {activePage === "add" && (
          <form onSubmit={handleSubmit} className="product-form">
            <h3>{editingProduct ? "✏️ Edit Product" : "➕ Add New Product"}</h3>

            <div className="form-grid">
              <div className="form-group">
                <label>Product Name</label>
                <input
                  type="text"
                  name="name"
                  placeholder="Enter product name"
                  value={form.name}
                  onChange={handleChange}
                  required
                />
              </div>

              <div className="form-group">
                <label>Category</label>
                <select name="category" value={form.category} onChange={handleChange} required>
                  <option value="Earphone">Earphone</option>
                  <option value="Smartphone">Smartphone</option>
                  <option value="Laptop">Laptop</option>
                  <option value="Smartwatch">Smartwatch</option>
                  <option value="Other">Other</option>
                </select>
              </div>

              <div className="form-group full-width">
                <label>Description</label>
                <textarea name="description" placeholder="Enter product description" value={form.description} onChange={handleChange} />
              </div>

              <div className="form-group">
                <label>Price (₹)</label>
                <input type="number" name="price" placeholder="0" value={form.price} onChange={handleChange} required />
              </div>

              <div className="form-group">
                <label>Offer Price (optional)</label>
                <input type="number" name="offerPrice" placeholder="0" value={form.offerPrice} onChange={handleChange} />
              </div>

              <div className="form-group full-width">
                <label>Image URL</label>
                <input type="text" name="image" placeholder="https://example.com/product.jpg" value={form.image} onChange={handleChange} required />
              </div>
            </div>

            {form.image && (
              <div className="preview">
                <p>Preview:</p>
                <img src={form.image} alt="Preview" onError={(e)=>{ e.currentTarget.style.display='none'; }} />
              </div>
            )}

            <div className="form-actions">
              <button type="submit" className="submit-btn">
                {editingProduct ? "Update Product" : "Add Product"}
              </button>
              {editingProduct && (
                <button type="button" className="cancel-btn" onClick={handleCancelEdit}>
                  Cancel
                </button>
              )}
            </div>
          </form>
        )}

        {activePage === "list" && (
          <>
            <h3 className="list-title">📦 Your Products</h3>
            {products.length === 0 ? (
              <p>No products yet.</p>
            ) : (
              <ul className="product-list">
                {products.map((product) => (
                  <li key={product._id} className="product-item">
                    <img src={product.image} alt={product.name} />
                    <div className="product-info">
                      <h4>{product.name}</h4>
                      <p>₹{product.price}{product.offerPrice ? `  • Offer: ₹${product.offerPrice}` : ""}</p>
                      <span className="category">{product.category}</span>
                    </div>

                    <div className="actions">
                      <button onClick={() => handleEdit(product)} className="edit-btn">✏️ Edit</button>
                      <button onClick={() => handleDelete(product._id)} className="delete-btn">🗑️ Delete</button>
                    </div>
                  </li>
                ))}
              </ul>
            )}
          </>
        )}

        {/* if user navigates to add after saving, show list too */}
        {activePage === "add" && (
          <>
            <h3 className="list-title">📦 Your Products (preview)</h3>
            <ul className="product-list small">
              {products.slice(0, 6).map((p) => (
                <li key={p._id} className="product-item small">
                  <img src={p.image} alt={p.name} />
                  <div className="product-info">
                    <h4>{p.name}</h4>
                    <p>₹{p.price}</p>
                  </div>
                </li>
              ))}
            </ul>
          </>
        )}
      </main>
    </div>
  );
}

export default SellerDashboard;
